  riven: { diff: "EVEN", tone: "#e8b84b", tldr: "Bait her stun \u2014 flow-trade when her dashes are down.", breakdown: "Bait her W stun, flow-trade, and EQ-R when her mobility is spent.", dos: ["Bait her W stun", "Flow-trade with shield up", "EQ-R when her dashes are down"], donts: ["Get W-stunned", "Fight her R burst raw", "Chase her dashes"], key: { slot: "W", name: "Ki Burst (Stun)", cd: "11s", note: "Her engage CC. Bait it.", winT: "KI BURST DOWN", winS: "EQ-R her." }, hold: "Hold nothing to Wind Wall \u2014 her kit is melee; bait her W and flow-trade when her dashes are spent.", tip: "Bait her W-stun, flow-trade with the shield up, and EQ-R her when her dashes are down.", win: "Bait her stun and flow-trade her." },
  tryndamere: { diff: "TRICKY", tone: "#ff8b3d", tldr: "Anti-heal his crits \u2014 EQ-R after his R, you can\u2019t out-stat him.", breakdown: "Anti-heal his crit healing, bait his R, and EQ-R after Undying Rage.", dos: ["Anti-heal his crit healing", "Bait his R, then EQ-R", "Flow-trade with shield up"], donts: ["Fight without anti-heal", "Burst him into his R", "Chase his spin blind"], key: { slot: "R", name: "Undying Rage", cd: "110s", note: "Unkillable 5s. EQ-R after it.", winT: "UNDYING RAGE DOWN", winS: "EQ-R him." }, hold: "Hold nothing to Wind Wall \u2014 his kit is melee; anti-heal his crits and EQ-R after his R ends.", tip: "Anti-heal his crit healing, bait his R, then EQ-R as it expires \u2014 catch his spin so he can\u2019t flee.", win: "Anti-heal and EQ-R after his R." },
  vayne: { diff: "EVEN", tone: "#e8b84b", tldr: "Wind Wall is huge \u2014 block her autos + condemn, all-in early.", breakdown: "Wind Wall blocks her autos AND condemn. All-in early with EQ-R before she scales.", dos: ["Wind Wall her autos + condemn", "EQ-R all-in early", "Close the gap fast"], donts: ["Get kited and condemned", "Fight her at 2 items", "Waste W on nothing"], key: { slot: "E", name: "Condemn", cd: "18s", note: "Projectile \u2014 Wind Wall blocks it!", winT: "CONDEMN DOWN", winS: "EQ-R her." }, hold: "Hold Wind Wall for her engage \u2014 it blocks her autos AND her condemn, shutting off her entire kit for its duration.", tip: "Wind Wall is a hard counter to her ranged kit \u2014 block her autos + condemn, then EQ-R all-in before she scales.", win: "Wall her autos and all-in early." },
